[Fact]
public void ShouldRenderPocoDataInVariousStylesWithConfigurableAlignment()
{
    var items = new[]
    {
        new { Name = "John Doe", Age = 42 },
        new { Name = "Jane Doe", Age = 38 }
    };

    using (var writer = new StringWriter())
    {
        var table = ConsoleTable.From(items);

        table.Configure(options =>
        {
            options.OutputTo = writer;
            options.NumberAlignment = Alignment.Right;
        });

        // Act & Assert: Default style
        table.Write(Format.Default);
        var defaultOutput = writer.ToString();
        Assert.Contains("John Doe", defaultOutput);
        Assert.Contains("Age", defaultOutput);

        // Act & Assert: Alternative style
        writer.GetStringBuilder().Clear();
        table.Write(Format.Alternative);
        var alternativeOutput = writer.ToString();
        Assert.Contains("+", alternativeOutput);

        // Act & Assert: Minimal style
        writer.GetStringBuilder().Clear();
        table.Write(Format.Minimal);
        var minimalOutput = writer.ToString();
        Assert.NotNull(minimalOutput);
        Assert.NotEmpty(minimalOutput);
        Assert.DoesNotContain("+", minimalOutput);
    }
}

