[Fact]
public void AddRow_ShouldThrowException_WhenColumnsAreNotSetOrCountIsMismatched()
{
    var table = new ConsoleTable();

    var ex1 = Assert.Throws<Exception>(() => table.AddRow("Value1"));
    Assert.Equal("Please set the columns first", ex1.Message);

    table.AddColumn(new[] { "Column1", "Column2" });

    var ex2 = Assert.Throws<Exception>(() => table.AddRow("Value1"));
    Assert.Equal("The number columns in the row (2) does not match the values (1)", ex2.Message);
}

[Fact]
public void ShouldWrapContentAtWordBreakDelimiterToPreventWordSplitting()
{
    var table = new ConsoleTable("Column")
        .Configure(o => o.EnableCount = true);
    table.MaxWidth = 10;
    table.AddRow("LongWord IsHere");

    var result = table.ToString();

    // Column length calculated before wrap: 15 (length of "LongWord IsHere")
    // Row format: " | {0,-15} |" -> Length 20
    // Divider dashes: 20 - 1 = 19 dashes
    // Header "Column" (6) + 9 spaces = 15
    // Row 1 "LongWord" (8) + 7 spaces = 15
    // Row 2 "IsHere" (6) + 9 spaces = 15

    Assert.Equal(
        """
         ------------------- 
         | Column          |
         ------------------- 
         | LongWord        |
         ------------------- 
         | IsHere          |
         ------------------- 

         Count: 2
        """, 
        result
    );
}

