[Fact]
public void Table_FromDictionary_SupportsHeterogeneousDataTypes()
{
    var data = new Dictionary<string, Dictionary<string, object>>
    {
        {
            "Row1", new Dictionary<string, object>
            {
                { "MixedA", 100 },
                { "MixedB", "Value1" }
            }
        },
        {
            "Row2", new Dictionary<string, object>
            {
                { "MixedA", false },
                { "MixedB", 99.9m }
            }
        }
    };

    var table = ConsoleTable.FromDictionary(data);

    Assert.Equal(3, table.Columns.Count);
    Assert.Equal(2, table.Rows.Count);
    Assert.Equal("", table.Columns[0]);
    Assert.Equal("MixedA", table.Columns[1]);
    Assert.Equal("MixedB", table.Columns[2]);

    Assert.Equal("Row1", table.Rows[0][0]);
    Assert.Equal(100, table.Rows[0][1]);
    Assert.Equal("Value1", table.Rows[0][2]);

    Assert.Equal("Row2", table.Rows[1][0]);
    Assert.Equal(false, table.Rows[1][1]);
    Assert.Equal(99.9m, table.Rows[1][2]);
}

