[Fact]
public void ShouldCorrectlyInitializeConsoleTableFromDiverseDataSources()
{
    // 1. Test List<T>
    var users = new List<User>
    {
        new() { Name = "Alexandre", Age = 36 }
    };
    var tableFromList = ConsoleTable.From(users);
    Assert.NotNull(tableFromList);
    Assert.Single(tableFromList.Rows);

    // 2. Test DataTable
    var dataTable = new DataTable();
    dataTable.Columns.Add("A", typeof(bool));
    dataTable.Rows.Add(true);
    var tableFromDataTable = ConsoleTable.From(dataTable);
    Assert.NotNull(tableFromDataTable);
    Assert.Equal("A", tableFromDataTable.Columns[0]);

    // 3. Test Object Array (First array is header, subsequent are rows)
    var objectArray = new object[][]
    {
        new object[] { "Header1", "Header2" },
        new object[] { "Value1", "Value2" }
    };
    var tableFromArray = ConsoleTable.From(objectArray);
    Assert.NotNull(tableFromArray);
    Assert.Single(tableFromArray.Rows);

    // 4. Test Dictionary
    var dictionary = new Dictionary<string, Dictionary<string, object>>
    {
        { "Key1", new Dictionary<string, object> { { "Col1", "Data1" } } }
    };
    var tableFromDict = ConsoleTable.FromDictionary(dictionary);
    Assert.NotNull(tableFromDict);
    Assert.Contains("Key1", (string)tableFromDict.Rows[0][0]);
}

[Fact]
        public void ShouldVerifySupportForStandardMarkdownAndMinimalFormats()
        {
            var table = new ConsoleTable("Prop", "Val")
                .AddRow("Data", 100);

            var standardOutput = table.ToString();
            var markdownOutput = table.ToMarkDownString();
            var minimalOutput = table.ToMinimalString();

            // Assert Standard Format (Default ToString contains borders and count)
            Assert.Contains("| Prop | Val |", standardOutput);
            Assert.Contains("-----------------", standardOutput);
            Assert.Contains("Count: 1", standardOutput);

            // Assert Markdown Format (Contains pipes and markdown header separator)
            Assert.Contains("| Prop | Val |", markdownOutput);
            Assert.Contains("|---|---|", markdownOutput);
            Assert.Contains("| Data | 100 |", markdownOutput);

            // Assert Minimal Format (Contains headers and data but no vertical pipe borders)
            Assert.Contains("Prop  Val", minimalOutput);
            Assert.Contains("---------", minimalOutput);
            Assert.DoesNotContain("|", minimalOutput);
        }

[Fact]
        public void TableOutputDestinationShouldDefaultToConsoleOutAndBeConfigurableToAnyTextWriter()
        {
            var table = new ConsoleTable("Header");
            table.AddRow("Value");

            // Verify default behavior
            Assert.Equal(table.Options.OutputTo, Console.Out);

            // Verify configurability to any TextWriter (using StringWriter)
            var customWriter = new StringWriter();
            table.Configure(o => o.OutputTo = customWriter);

            Assert.Equal(table.Options.OutputTo, customWriter);

            table.Write();

            // Verify that the output was actually directed to the configured writer
            var output = customWriter.ToString();
            Assert.NotEmpty(output);
            Assert.Contains("Header", output);
            Assert.Contains("Value", output);
        }
